`,r.jsxs(Hr,{title:"Aufgabe: Werte im Dezimalsystem berechnen",children:[r.jsx(e.p,{children:"Berechnen Sie die folgenden Werte im Dezimalsystem:"}),r.jsxs(e.ul,{children:[`
