`,r.jsxs(e.li,{children:["Es verwendet ",r.jsx(e.code,{children:"Markdown"})," als Syntax für die Notizen"]}),`
`,r.jsx(e.li,{children:"Alle Dateien gehören dem Benutzer"}),`
`,r.jsx(e.li,{children:"Alle Notizen können auch ohne Obsidian gelesen und geändert werden"}),`
